// src/components/Common/cvsection.js
import React, { useState } from "react";

export default function CVSection({ workerInfo, isEditable = false, onSave }) {
  const [editedInfo, setEditedInfo] = useState({ ...workerInfo });
  const [newSkill, setNewSkill] = useState("");
  const [showEditModal, setShowEditModal] = useState(false);

  const addSkill = () => {
    if (newSkill.trim() && !editedInfo.skills.includes(newSkill.trim())) {
      setEditedInfo({ ...editedInfo, skills: [...editedInfo.skills, newSkill.trim()] });
      setNewSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setEditedInfo({ ...editedInfo, skills: editedInfo.skills.filter(skill => skill !== skillToRemove) });
  };

  const handleSave = () => {
    if (onSave) onSave(editedInfo);
    setShowEditModal(false);
    alert("✅ CV mis à jour avec succès!");
  };

  const styles = `
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
    }
    
    .modal-overlay {
      position: fixed !important;
      top: 0 !important;
      left: 0 !important;
      right: 0 !important;
      bottom: 0 !important;
      background: rgba(0, 0, 0, 0.9) !important;
      backdrop-filter: blur(12px) !important;
      z-index: 10000 !important;
      display: flex !important;
      align-items: center !important;
      justify-content: center !important;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
  `;

  const CVContent = () => (
    <div style={{ textAlign: 'center' }}>
      <div className="text-6xl mb-4">👩‍💻</div>
      <h2 className="text-2xl font-bold text-white mb-2">{workerInfo.name}</h2>
      <p className="text-green-400 mb-4">{workerInfo.role}</p>
      <div className="text-left">
        <h3 className="text-xl font-bold text-white mt-4 mb-2">📋 Profil</h3>
        <p className="text-gray-300">{workerInfo.bio}</p>
        
        <h3 className="text-xl font-bold text-white mt-4 mb-2">💪 Compétences</h3>
        <div className="flex flex-wrap gap-2">
          {workerInfo.skills.map((skill, i) => (
            <span key={i} className="skill-tag">{skill}</span>
          ))}
        </div>
        
        <h3 className="text-xl font-bold text-white mt-4 mb-2">📞 Contact</h3>
        <p className="text-gray-300">📧 {workerInfo.email}</p>
        <p className="text-gray-300">📱 {workerInfo.phone}</p>
        
        <h3 className="text-xl font-bold text-white mt-4 mb-2">🎓 Expérience</h3>
        <p className="text-gray-300">{workerInfo.experience}</p>
      </div>
      {isEditable && (
        <button onClick={() => setShowEditModal(true)} className="btn-primary w-full mt-4">
          ✏️ Modifier CV
        </button>
      )}
    </div>
  );

  const EditModal = () => (
    <div className="modal-overlay" onClick={() => setShowEditModal(false)}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <button onClick={() => setShowEditModal(false)} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-6xl mb-4">✏️</div>
          <h2 className="text-2xl font-bold text-white mb-4">Modifier le CV</h2>
        </div>
        <div className="edit-cv-form">
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">👤 Nom complet</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.name} onChange={(e) => setEditedInfo({...editedInfo, name: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💼 Titre du poste</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.role} onChange={(e) => setEditedInfo({...editedInfo, role: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📧 Email</label>
            <input type="email" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.email} onChange={(e) => setEditedInfo({...editedInfo, email: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📱 Téléphone</label>
            <input type="tel" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.phone} onChange={(e) => setEditedInfo({...editedInfo, phone: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📍 Localisation</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.location} onChange={(e) => setEditedInfo({...editedInfo, location: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📝 Bio</label>
            <textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" rows="3" value={editedInfo.bio} onChange={(e) => setEditedInfo({...editedInfo, bio: e.target.value})} />
          </div>
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💪 Compétences</label>
            <div className="flex flex-wrap gap-2 mb-2">
              {editedInfo.skills.map((skill, i) => (
                <span key={i} className="skill-tag" style={{ display: 'inline-flex', alignItems: 'center', gap: '5px' }}>
                  {skill}
                  <button onClick={() => removeSkill(skill)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '14px' }}>✕</button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input type="text" className="flex-1 p-2 rounded-xl bg-white/10 text-white border border-green-500/30" placeholder="Ajouter une compétence" value={newSkill} onChange={(e) => setNewSkill(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && addSkill()} />
              <button onClick={addSkill} className="btn-primary">+ Ajouter</button>
            </div>
          </div>
          <button onClick={handleSave} className="btn-primary w-full mt-4">💾 Enregistrer</button>
        </div>
      </div>
    </div>
  );

  return (
    <>
      <style>{styles}</style>
      <CVContent />
      {showEditModal && <EditModal />}
    </>
  );
}
